section.programlisting:
1 #ifndef HDEF_FMODWRAPPER
2 #define HDEF_FMODWRAPPER
3 
4 #include "IAudioManager.h"
5 
6 #include <fmod_common.h>
7 #include <fmod_studio_common.h>
8 #include <vector>
9 #include <string>
10 #include <memory>
11 #include <unordered_map>
12 #include <sol/sol.hpp>
13 
14 struct FMOD_STUDIO_SYSTEM;
15 struct FMOD_STUDIO_BANK;
16 struct FMOD_STUDIO_EVENTDESCRIPTION;
17 struct FMOD_STUDIO_EVENTINSTANCE;
18 
19 namespace Mochi::FS
20 {
21     class PackCatalog;
22 }
23 namespace Mochi::Scripting
24 {
25     class ScriptingManager;
26 }
27 namespace Mochi::Audio
28 {
29     struct FMODMarkerEvent
30     {
31         const char *MarkerName;
32         int MarkerPosition;
33     };
34     class FMODWrapper : public IAudioManager
35     {
36     private:
37         struct FMOD_Bank_Pair
38         {
39             FMOD_STUDIO_BANK *bank;
40             FMOD_STUDIO_BANK *stringsBank;
41         };
42 
43         FMOD_STUDIO_SYSTEM *mFmodSystem;
44         FMOD_STUDIO_EVENTDESCRIPTION *mBgmEventDescription;
45         FMOD_STUDIO_EVENTINSTANCE *mBgmEventInstance;
46         std::vector<FMOD_Bank_Pair> mBankPairs;
47         std::unordered_map<std::string, FMOD_Bank_Pair> mBankPairsMap;
48         static FMOD_RESULT F_CALL EventCallback(FMOD_STUDIO_EVENT_CALLBACK_TYPE type, FMOD_STUDIO_EVENTINSTANCE *event, void *parameters);
49         void OnEventCallback(FMOD_STUDIO_EVENT_CALLBACK_TYPE type, FMOD_STUDIO_EVENTINSTANCE *event, void *parameters);
50         FS::PackCatalog *mCatalog;
51         Scripting::ScriptingManager *mScripting;
52         std::unordered_map<std::string, FMOD_STUDIO_EVENTDESCRIPTION *> mSoundCache;
53         std::unordered_map<std::string, FMOD_STUDIO_BUS *> mBusesCache;
54 
55         void LoadBank(const std::string &bankName);
56         void UnloadBank(const std::string &bankName);
57         void SetBusVolume(const std::string &busGroupName, const float &value);
58 
59         std::vector<FMODMarkerEvent> mEventQueue;
60 
61     public:
62         FMODWrapper(FS::PackCatalog *, Scripting::ScriptingManager *);
63         virtual ~FMODWrapper();
64         virtual void Update(const float &dt) override;
65         virtual void LoadAudio(const std::string &path) override { LoadBank(path); }
66         virtual void UnloadAudio(const std::string &path) override { UnloadBank(path); };
67         virtual void PlayBGM(const std::string &eventName) override;
68         virtual void PauseBGM() override;
69         virtual void ResumeBGM() override;
70         virtual void StopBGM() override;
71         virtual void SkipToTimelinePosition(const int &ms) override;
72         virtual void PlayOneShot(const std::string &eventName) override;
73         void ClearSoundCache() { mSoundCache.clear(); }
74         void ClearBusCache() { mBusesCache.clear(); }
75         virtual void SetParameter(const std::string &parameterName, const float &value) override;
76         virtual void SetMixerVolume(const std::string &busGroupName, const float &value) override { SetBusVolume(busGroupName, value); };
77     };
78 }
79 
80 #endif
